// idが"example"の要素のclass属性を取得
let attr = document.getElementById('example').getAttribute('class');
// このコードを実行すると、idが"example"の要素のclass属性の値を取得することができます。

// idが"example"の要素にclass属性を設定
document.getElementById('example').setAttribute('class', 'new-class');
// このコードを実行すると、idが"example"の要素にclass属性が設定され、その値は'new-class'となります。

// idが"example"の要素のclass属性を削除
document.getElementById('example').removeAttribute('class');
// このコードを実行すると、idが"example"の要素のclass属性が削除されます。

// idが"example"の要素がclass属性を持っているか確認
let hasAttr = document.getElementById('example').hasAttribute('class');
// このコードを実行すると、idが"example"の要素がclass属性を持っているかどうかの真偽値が取得できます。

// idが"example"の要素に新たなクラスを追加
document.getElementById('example').classList.add('new-class');
// このコードを実行すると、idが"example"の要素に'new-class'というクラスが追加されます。

// idが"example"の要素から特定のクラスを削除
document.getElementById('example').classList.remove('class-to-remove');
// このコードを実行すると、idが"example"の要素から'class-to-remove'というクラスが削除されます。

// idが"example"の要素で特定のクラスをトグル
document.getElementById('example').classList.toggle('class-to-toggle');
// このコードを実行すると、idが"example"の要素で'class-to-toggle'というクラスが存在する場合はそのクラスが削除され、存在しない場合はそのクラスが追加されます。

// idが"example"の要素が特定のクラスを持っているか確認
let hasClass = document.getElementById('example').classList.contains('class-to-check');
// このコードを実行すると、idが"example"の要素が'class-to-check'というクラスを持っているかどうかの真偽値が取得できます。

// idが"example"の要素に新たなクラスを追加
document.getElementById('example').classList.add('new-class1', 'new-class2');
// このコードを実行すると、idが"example"の要素に'new-class1'と'new-class2'というクラスが追加されます。

// idが"example"の要素から特定のクラスを削除
document.getElementById('example').classList.remove('class-to-remove1', 'class-to-remove2');
// このコードを実行すると、idが"example"の要素から'class-to-remove1'と'class-to-remove2'というクラスが削除されます。
